import{c as o,Q as r,j as u,m as a}from"./chunks/framework.DpF7k2f3.js";const d=JSON.parse('{"title":"第2章 为什么\\"先混进去\\"是理性策略","description":"","frontmatter":{"outline":[2,3]},"headers":[],"relativePath":"zh/part1-cognition/chapter2.md","filePath":"zh/part1-cognition/chapter2.md"}'),n={name:"zh/part1-cognition/chapter2.md"};function q(p,t,i,l,e,s){return r(),u("div",null,[...t[0]||(t[0]=[a('<h1 id="第2章-为什么-先混进去-是理性策略" tabindex="-1">第2章 为什么&quot;先混进去&quot;是理性策略 <a class="header-anchor" href="#第2章-为什么-先混进去-是理性策略" aria-label="Permalink to &quot;第2章 为什么&quot;先混进去&quot;是理性策略&quot;">​</a></h1><h2 id="本章你能带走什么" tabindex="-1">本章你能带走什么 <a class="header-anchor" href="#本章你能带走什么" aria-label="Permalink to &quot;本章你能带走什么&quot;">​</a></h2><p>读完上一章，你已经知道AI应用开发没有想象中那么高不可攀。但我猜你现在还是有点犹豫——&quot;我知道门槛没我想的那么高，但我还是觉得自己没准备好&quot;。</p><p>这很正常。我见过太多人在&quot;准备&quot;这件事上一拖就是半年一年，等他觉得准备好了，机会窗口早关了。</p><p>这一章我要跟你掰开揉碎讲清楚一件事：<strong>在AI应用开发这个领域，&quot;先混进去&quot;不是赌博，是效率最高的理性策略</strong>。</p><p>具体来说你会理解：</p><ul><li>为什么AI技术的技能半衰期短得离谱，等你准备好黄花菜都凉了</li><li>为什么企业真正想要的是&quot;能干活的人&quot;而不是&quot;全懂的人&quot;</li><li>为什么边干边学的效率是闭门苦读的2-3倍</li><li>为什么&quot;我不够格&quot;这种感觉是个幻觉，以及怎么跟它和平共处</li></ul><hr><h2 id="_2-1-ai应用开发的技能半衰期极短-等准备好就来不及了" tabindex="-1">2.1 AI应用开发的技能半衰期极短，等准备好就来不及了 <a class="header-anchor" href="#_2-1-ai应用开发的技能半衰期极短-等准备好就来不及了" aria-label="Permalink to &quot;2.1 AI应用开发的技能半衰期极短，等准备好就来不及了&quot;">​</a></h2><p>先说个我亲眼见证的事实。</p><p>2022年10月，LangChain刚发布的时候，我有个朋友花了整整3个月把这套框架学透，做了十几个demo，简历上写得明明白白：&quot;精通LangChain&quot;。2023年初他靠着这个成功跳槽，薪资涨了40%。</p><p>然后呢？2024年，LangChain团队发布了LangGraph，这是完全不同的架构。2025年10月，LangChain直接发布1.0版本，整个框架从零重写。你猜怎么着？他那3个月学的东西，大部分直接作废了。</p><p><strong>这就是AI应用开发的残酷现实：你在学的东西，在你还没学完的时候可能就已经过时了。</strong></p><h3 id="数据会说话" tabindex="-1">数据会说话 <a class="header-anchor" href="#数据会说话" aria-label="Permalink to &quot;数据会说话&quot;">​</a></h3><p>据IBM商业价值研究院的报告，生成式AI的普及将推动最大规模的员工技能重塑，预计未来三年内，全球有40%的劳动力需要重新学习技能。<strong>技能半衰期从过去的5-7年缩短到了2-3年。</strong></p><p>这意味着什么？意味着你在2024年初花6个月系统学习的某个框架，到2026年可能已经被彻底淘汰或被竞品完全取代。你花大量时间&quot;系统准备&quot;的东西，很可能在真正派上用场之前就已经折旧完毕。</p><p>再看一个更扎心的数据：Corporate Executive Board的研究显示，<strong>员工在正式培训中学习的内容，90%会在一周内遗忘</strong>。而通过真实工作场景习得的知识，遗忘速度要慢得多。</p><h3 id="框架迭代的速度有多快" tabindex="-1">框架迭代的速度有多快 <a class="header-anchor" href="#框架迭代的速度有多快" aria-label="Permalink to &quot;框架迭代的速度有多快&quot;">​</a></h3><p>让我用LangChain的进化史给你算一笔时间账：</p><table tabindex="0"><thead><tr><th>时间</th><th>版本</th><th>重大变化</th><th>之前学的还剩多少有用</th></tr></thead><tbody><tr><td>2022年10月</td><td>LangChain 0.x诞生</td><td>定义Chains、Agents、Memory核心抽象</td><td>-</td></tr><tr><td>2023年4月</td><td>融资公司化</td><td>生态爆炸式增长，集成300+服务</td><td>30%</td></tr><tr><td>2023年10月</td><td>LCEL推出</td><td>管道符语法，声明式组合</td><td>基础概念保留，API大幅变化</td></tr><tr><td>2024年1-5月</td><td>v0.1/v0.2</td><td>AgentExecutor被标记废弃，推荐LangGraph</td><td>核心API已弃用</td></tr><tr><td>2024年</td><td>LangGraph正式发布</td><td>图结构Agent编排，支持循环和条件分支</td><td>几乎要从头学</td></tr><tr><td>2025年10月</td><td>LangChain 1.0</td><td>全面重写，create_agent统一入口，引入Middleware</td><td><strong>几乎全部作废</strong></td></tr></tbody></table><p>三年时间，框架从&quot;五个函数做RAG&quot;到&quot;全面重写&quot;。你告诉我，<strong>你怎么准备？</strong></p><p>更讽刺的是，LangChain团队在1.0发布时承认：他们最初为了让开发者&quot;尽快用起来&quot;的设计，反而成了&quot;深度定制和规模化稳定&quot;的阻碍。那些&quot;高层次的易用接口&quot;在生产环境中反而成了坑。</p><h3 id="prompt工程的短暂春天" tabindex="-1">Prompt工程的短暂春天 <a class="header-anchor" href="#prompt工程的短暂春天" aria-label="Permalink to &quot;Prompt工程的短暂春天&quot;">​</a></h3><p>还记得Prompt工程师这个岗位吗？</p><p>2023年初ChatGPT爆火的时候，真有人靠&quot;调教&quot;AI聊天机器人拿到了高薪。一些猎头放话：&quot;prompt engineer，年薪50万起步&quot;。</p><p>结果呢？2024年初，Claude 3、GPT-4o、Gemini 1.5这些模型一出来，prompt engineer的需求直接腰斩——<strong>模型变聪明了，不需要那么多&quot;咒语&quot;了</strong>。</p><p>这波红利期的窗口有多短？满打满算不到18个月。</p><p>我见过有人花大价钱报班学&quot;Prompt工程秘籍&quot;，学完发现这些技巧大部分已经被模型更新抹平了。现在你要做的是理解模型能力边界，而不是背诵一堆&quot;咒语模板&quot;。</p><h3 id="为什么-准备好-是个伪命题" tabindex="-1">为什么&quot;准备好&quot;是个伪命题 <a class="header-anchor" href="#为什么-准备好-是个伪命题" aria-label="Permalink to &quot;为什么&quot;准备好&quot;是个伪命题&quot;">​</a></h3><p>很多人陷入了一个思维陷阱：<strong>认为必须把所有知识都学到位了，才能去工作</strong>。</p><p>但AI应用开发的知识体系有几个特点，让这种想法变成了一场注定失败的自我折磨：</p><ol><li><strong>知识边界在不断扩展和变化</strong>。你现在学的，可能是半年后要淘汰的。</li><li><strong>实践知识比理论知识重要得多</strong>。你知道RAG的原理，但没跑通过实际项目，遇到问题还是抓瞎。</li><li><strong>真实问题来自真实场景</strong>。你在书本上永远学不到&quot;客户非说AI回答的不对但其实就是用户输入错了&quot;这种糟心事。</li><li><strong>团队协作是隐性知识</strong>。代码规范、需求沟通、技术方案对齐，这些只能在实际工作中习得。</li></ol><p><strong>结论：你在家里准备得再充分，上班第一天也会发现自己是个菜鸟。而你在工作中踩的每一个坑，都是最有效的学习。</strong></p><hr><h2 id="_2-2-企业真正要的是-能干活的人-不是-全懂的人" tabindex="-1">2.2 企业真正要的是&quot;能干活的人&quot;，不是&quot;全懂的人&quot; <a class="header-anchor" href="#_2-2-企业真正要的是-能干活的人-不是-全懂的人" aria-label="Permalink to &quot;2.2 企业真正要的是&quot;能干活的人&quot;，不是&quot;全懂的人&quot;&quot;">​</a></h2><p>很多人以为面试官在找一个&quot;什么都懂&quot;的人。</p><p>大错特错。</p><p>正如第1章所分析的，JD中的&quot;硬门槛&quot;其实比你想象的软得多。现在我要告诉你更深一层：<strong>企业真正在找的，是一个能解决问题的人，而不是一个会考试的人</strong>。</p><h3 id="企业的真实困境" tabindex="-1">企业的真实困境 <a class="header-anchor" href="#企业的真实困境" aria-label="Permalink to &quot;企业的真实困境&quot;">​</a></h3><p>我跟你说实话：企业招聘一个AI应用开发工程师，不是想找一个&quot;AI专家&quot;，而是想找一个<strong>能解决问题的人</strong>。</p><p>他们的代码库里有一堆乱七八糟的RAG实现，效果不好，没人能维护。他们想推一个AI功能，产品经理催，运营催，老板问&quot;什么时候能用&quot;，技术团队还在争论用LangChain还是LlamaIndex。</p><p>他们需要的是：<strong>有人能把这事干完、干好，而不是有人能把这事讲得头头是道</strong>。</p><p>据51CTO的一篇分析文章指出，在AI时代，<strong>头部企业已转向优先录用具备AI应用能力的新锐人才，而非传统的&quot;精通XX工具&quot;的技能清单型候选人</strong>。企业真正看重的是三种核心能力：</p><ol><li><strong>上下文赋能（Contextual Intelligence）</strong>：把业务问题&quot;翻译&quot;成AI能理解的形式</li><li><strong>敏捷学习力（Agile Learning Agility）</strong>：快速定义问题、快速学习最小必要知识</li><li><strong>终局负责人（End-to-End Ownership）</strong>：对最终结果负责，而不是&quot;交接棒&quot;心态</li></ol><h3 id="jd写的和实际要的是两码事" tabindex="-1">JD写的和实际要的是两码事 <a class="header-anchor" href="#jd写的和实际要的是两码事" aria-label="Permalink to &quot;JD写的和实际要的是两码事&quot;">​</a></h3><p>上一章我们详细分析了招聘JD里哪些是硬门槛、哪些是虚晃一枪。但我还要告诉你一个更残酷的事实：<strong>即便是那些&quot;硬门槛&quot;，真实要求也比字面意思宽松得多</strong>。</p><p>举几个例子：</p><p><strong>&quot;3年以上Python开发经验&quot;</strong></p><p>这条在社招时确实比较硬。但你知道实际工作中的&quot;3年经验&quot;是什么水平吗？很多简历上写着&quot;3年经验&quot;的工程师，写出来的代码bug一堆，代码规范一团糟，Git都不会用。</p><p>企业真正需要的是：<strong>能独立写出一个能跑的功能模块、遇到问题能debug、代码至少看起来像个正经工程师</strong>。这个要求，1年认真练习就能达到。</p><p><strong>&quot;熟悉LangChain/LlamaIndex等AI框架&quot;</strong></p><p>这句话的真实意思是：<strong>会用就行，不出事就行</strong>。</p><p>面试的时候，面试官问你&quot;用过LangChain吗&quot;，你回答&quot;用过，我用它做过RAG demo&quot;，这就够了。他们不会考你LangChain源码有几行、某个方法的具体参数有哪几个选项。</p><p><strong>&quot;有AIGC产品落地经验&quot;</strong></p><p>这条是2024-2025年最常见的&quot;虚假门槛&quot;。企业想找有经验的人，但2023年哪有什么AIGC产品落地？</p><p>所以这条的真实含义是：<strong>最好有demo，没demo的话有学习能力也行</strong>。关键看你能不能证明自己不是在&quot;纸上谈兵&quot;。</p><h3 id="企业招聘的真实逻辑" tabindex="-1">企业招聘的真实逻辑 <a class="header-anchor" href="#企业招聘的真实逻辑" aria-label="Permalink to &quot;企业招聘的真实逻辑&quot;">​</a></h3><p>我在跟几个招聘经理聊过之后，总结出他们的真实想法：</p><p><strong>&quot;我不指望招来的人什么都会。如果什么都会，我还招他来干嘛？他早就有更好的工作了。&quot;</strong></p><p><strong>&quot;我要的是：遇到没见过的问题，他能自己想办法解决。他不会的，可以学，但得有自学能力和解决实际问题的能力。&quot;</strong></p><p><strong>&quot;简历上写得再漂亮，不如GitHub上有一个能跑的项目。我就看他做的东西，问他几个问题，看他是不是真的理解。&quot;</strong></p><p>换句话说：<strong>企业愿意容忍你&quot;不会&quot;，但不愿意容忍你&quot;不能学&quot;</strong>。</p><p>而&quot;能不能学&quot;这件事，在面试之前根本看不出来。所以企业采取的策略是：<strong>先看态度，再看潜力，实在不行培养</strong>。</p><p>你要做的，不是展示一个完美的知识体系，而是展示：<strong>我愿意学、我能学会、我会动手做</strong>。</p><hr><h2 id="_2-3-边干边学的效率远超闭门苦读" tabindex="-1">2.3 边干边学的效率远超闭门苦读 <a class="header-anchor" href="#_2-3-边干边学的效率远超闭门苦读" aria-label="Permalink to &quot;2.3 边干边学的效率远超闭门苦读&quot;">​</a></h2><p>好，现在我们来聊聊学习方法。</p><p>你可能有两个选择：</p><p><strong>选择A</strong>：辞职或全职，花6个月把Python、RAG、LangChain、Agent、部署全部系统学一遍，然后去找工作。</p><p><strong>选择B</strong>：在职，找个切入口先进AI团队（哪怕是边缘项目），边干边学，快速积累实战经验。</p><p>如果你相信&quot;选择A更稳妥&quot;，我必须用数据和逻辑告诉你：<strong>你错了</strong>。</p><h3 id="科学数据告诉你为什么" tabindex="-1">科学数据告诉你为什么 <a class="header-anchor" href="#科学数据告诉你为什么" aria-label="Permalink to &quot;科学数据告诉你为什么&quot;">​</a></h3><p>Guild教育平台2025年的研究数据告诉我们一些扎心的结论：</p><ul><li><strong>71%的学习者报告说自从开始学习后感觉效率更高了</strong>——但前提是他们<strong>在工作中应用了所学</strong></li><li><strong>54%的学习者把新技能分享给了团队成员</strong>——实践倒逼了更深入的理解</li><li><strong>75%的学习者想在自己的组织内应用新技能</strong>——带着真实需求去学，事半功倍</li></ul><p>还有更直接的：</p><p>Corporate Executive Board的数据：<strong>员工在正式培训中学习的内容，90%会在一周内遗忘</strong>。而通过真实工作场景和社会化学习获得的知识，遗忘速度要慢得多。</p><p>这说明什么？<strong>离开真实场景的学习，是效率最低的学习方式</strong>。</p><h3 id="学习金字塔的残酷真相" tabindex="-1">学习金字塔的残酷真相 <a class="header-anchor" href="#学习金字塔的残酷真相" aria-label="Permalink to &quot;学习金字塔的残酷真相&quot;">​</a></h3><p>教育心理学有个&quot;学习金字塔&quot;（Cone of Learning）理论，这是美国国家训练实验室（National Training Laboratories）的经典研究成果。它揭示了一个简单但重要的道理：</p><table tabindex="0"><thead><tr><th>学习方式</th><th>平均留存率</th></tr></thead><tbody><tr><td>听讲（Lecture）</td><td>5%</td></tr><tr><td>阅读（Reading）</td><td>10%</td></tr><tr><td>视听（Audio-Visual）</td><td>20%</td></tr><tr><td>演示（Demonstration）</td><td>30%</td></tr><tr><td>讨论（Discussion）</td><td>50%</td></tr><tr><td>实践（Practice）</td><td>75%</td></tr><tr><td>教授他人（Teaching Others）</td><td><strong>90%</strong></td></tr></tbody></table><p>看明白了吗？<strong>你坐在家里看教程、看书、刷视频，留存率最高也就30%</strong>。</p><p>而你在工作中解决问题、把学到的东西用起来，留存率是75%。</p><p>这就是为什么很多人&quot;学了很多但还是不会&quot;——因为他们一直在金字塔的底部徘徊，根本没爬到上面去。</p><h3 id="实战案例-两种学习路径的对比" tabindex="-1">实战案例：两种学习路径的对比 <a class="header-anchor" href="#实战案例-两种学习路径的对比" aria-label="Permalink to &quot;实战案例：两种学习路径的对比&quot;">​</a></h3><p>让我给你讲两个真实的故事。</p><p><strong>故事A：小明的&quot;完美准备&quot;路线</strong></p><p>小明是个Java后端，想转AI应用开发。他决定先把基础打好。</p><ul><li>第1个月：学Python，把廖雪峰的教程过了一遍</li><li>第2个月：学机器学习基础，补吴恩达的课</li><li>第3个月：学深度学习基础，看了几本理论书</li><li>第4个月：学NLP基础，了解Transformer</li><li>第5个月：学LangChain，把官方文档啃完</li><li>第6个月：做项目，写简历，投简历</li></ul><p>半年后，他终于找到了一份AI应用开发的实习。但面试的时候，他发现自己学的很多东西在工作中根本用不上，而工作中需要的东西他很多都没学过。</p><p><strong>时间成本：6个月全职学习 + 1个月找工作</strong></p><p><strong>故事B：小红的&quot;先混进去&quot;路线</strong></p><p>小红也是Java后端，但她选择了另一条路。</p><ul><li>第1个月：花两周学Python基础（够用就行），然后花两周学LangChain入门（做demo）</li><li>第2个月：在公司内部转岗到AI项目组（哪怕是从边缘项目开始），边干边学</li><li>第3-4个月：第一个RAG项目，从0到1完整跟下来，遇到问题就查文档、问同事、搜Google</li><li>第5个月：开始主动承担更多任务，了解生产环境的代码规范和部署流程</li><li>第6个月：跳槽到更好的AI公司，面试时能讲出完整的项目经历</li></ul><p><strong>时间成本：1个月业余时间学习 + 5个月边干边学 + 1个月跳槽</strong></p><p>你猜谁的成长更快？谁的经验更值钱？</p><p>答案是小红。她的6个月，是实打实的6个月项目经验。小明的6个月，有3个月在学&quot;可能永远用不到&quot;的东西。</p><h3 id="边干边学的复利效应" tabindex="-1">边干边学的复利效应 <a class="header-anchor" href="#边干边学的复利效应" aria-label="Permalink to &quot;边干边学的复利效应&quot;">​</a></h3><p>更重要的是：<strong>边干边学是复利增长的，而闭门苦读是线性积累的</strong>。</p><p>什么意思？</p><p>你进入AI团队后，第一个月可能只学会了&quot;怎么调用API&quot;。但这个技能让你能做第一个项目，第一个项目让你能做第二个项目，第二个项目让你接触到更复杂的场景......</p><p>每一段经历都为下一段经历赋能。你的经验不是累加的，是<strong>相乘的</strong>。</p><p>而闭门苦读呢？你学完Python学RAG，学完RAG学LangChain，每一段学习是独立计算的。你学会的东西很难直接转化为&quot;解决问题的能力&quot;，因为你没有解决过真实问题。</p><h3 id="怎么做到-边干边学" tabindex="-1">怎么做到&quot;边干边学&quot; <a class="header-anchor" href="#怎么做到-边干边学" aria-label="Permalink to &quot;怎么做到&quot;边干边学&quot;&quot;">​</a></h3><p>我理解你的顾虑：&quot;边干边学听起来很好，但我怎么进入那个&#39;干&#39;的状态？&quot;</p><p>有几个实操策略：</p><p><strong>策略1：从&quot;AI相关&quot;的边缘项目切入</strong></p><p>不一定非要直接做AI开发。你可以先做&quot;AI周边&quot;的工作：</p><ul><li>测试AI功能（AI应用需要大量测试，幻觉检测、输出质量评估都是稀缺能力）</li><li>做AI应用的数据标注和评估</li><li>维护AI项目的文档和配置</li><li>参与AI项目的需求分析和产品设计</li></ul><p>这些工作能让你接触到真实的AI项目，建立起对AI应用的直觉，为后续深入做准备。</p><p><strong>策略2：主动&quot;制造&quot;练习机会</strong></p><p>如果你现在的工作跟AI没关系，也不要干等着。</p><ul><li>用业余时间做AI demo，把项目代码放GitHub</li><li>用AI工具优化自己当前的工作流程（哪怕只是用ChatGPT写周报）</li><li>参与开源的AI项目，从修bug开始</li><li>帮别人解决AI相关的问题（教是最好的学）</li></ul><p><strong>策略3：带着问题学，而不是系统学</strong></p><p>假设你现在要做一个RAG项目。不要先去把&quot;RAG的理论知识&quot;全部学完，而是：</p><ol><li>快速了解RAG是什么（30分钟）</li><li>直接动手做一个最简单的demo（2小时）</li><li>遇到具体问题，再去查具体答案</li><li>跑通之后，再去理解原理</li></ol><p>这种&quot;Just-in-Time Learning&quot;（即时学习）比系统学习效率高得多，因为你的学习是目标导向的、问题驱动的。</p><hr><h2 id="_2-4-心理障碍拆解-冒名顶替综合征与-不够格-幻觉" tabindex="-1">2.4 心理障碍拆解：冒名顶替综合征与&quot;不够格&quot;幻觉 <a class="header-anchor" href="#_2-4-心理障碍拆解-冒名顶替综合征与-不够格-幻觉" aria-label="Permalink to &quot;2.4 心理障碍拆解：冒名顶替综合征与&quot;不够格&quot;幻觉&quot;">​</a></h2><p>好，上面讲的都是理性层面的分析。但我知道，很多人的真正障碍不在脑子，在心里。</p><p>你可能在想：<strong>&quot;道理我都懂，但我就是觉得自己不够格&quot;</strong>。</p><p>恭喜你，你这是得了&quot;冒名顶替综合征&quot;（Impostor Syndrome）。这是程序员和IT从业者中最普遍的心理现象之一。</p><h3 id="什么是冒名顶替综合征" tabindex="-1">什么是冒名顶替综合征 <a class="header-anchor" href="#什么是冒名顶替综合征" aria-label="Permalink to &quot;什么是冒名顶替综合征&quot;">​</a></h3><p>冒名顶替综合征是一种持久的心理状态，特征是：</p><ul><li>即使有客观的成功证据，仍然无法内化自己的成就</li><li>持续害怕被&quot;揭露&quot;为骗子</li><li>把成功归因于运气、时机或&quot;骗过了别人&quot;，而不是能力</li><li>感觉自己的不配感与实际成就之间的差距越来越大</li></ul><p>据心理学研究（Clance &amp; Imes, 1978首次提出该概念），<strong>约70%的人在人生某个阶段会经历冒名顶替综合征</strong>。而在IT行业，这个比例更高——因为：</p><ol><li><strong>技术更新太快，总有&quot;没学过的&quot;东西</strong>。你觉得&quot;我不知道的东西太多了&quot;，但其实每个人都是这样。</li><li><strong>行业崇拜&quot;天才程序员&quot;文化</strong>。你在社交媒体上看到的都是&quot;我24岁就做出了改变世界的项目&quot;的励志故事，让你觉得自己太差了。</li><li><strong>知识深度的幻觉</strong>。你深入一个领域越久，越发现自己的无知。这不是退步，恰恰是进步的标志。</li><li><strong>缺乏参照系</strong>。你只看到别人的&quot;成果&quot;，看不到别人的&quot;挣扎&quot;。</li></ol><h3 id="程序员冒名顶替综合征的特殊性" tabindex="-1">程序员冒名顶替综合征的特殊性 <a class="header-anchor" href="#程序员冒名顶替综合征的特殊性" aria-label="Permalink to &quot;程序员冒名顶替综合征的特殊性&quot;">​</a></h3><p>在IT行业，冒名顶替综合征有一些特殊的表现形式：</p><p><strong>&quot;他们发现我其实不会写代码&quot;</strong></p><p>真相：每个人都是从&quot;不会&quot;到&quot;会&quot;的。没有任何人是天生的程序员。你现在&quot;不会&quot;的，可能那个人当初也不会，只是他开始得更早而已。</p><p><strong>&quot;我能进来只是运气好&quot;</strong></p><p>真相：如果你的面试通过了、项目交付了、客户满意了，那不叫运气，那叫能力。运气可以让你进门，但没法让你持续产出。</p><p><strong>&quot;再过几天他们就会发现我是个骗子&quot;</strong></p><p>真相：如果你是骗子，你不会有这种担忧。真正的骗子不会觉得自己是骗子。正是因为你知道自己&quot;有不知道的东西&quot;，才说明你在认真对待这份工作。</p><p><strong>&quot;周围的人都很厉害，我太差了&quot;</strong></p><p>真相：你的参照系可能有问题。你在跟公司里最优秀的人比，当然显得差。但你招进来不是因为你比所有人都强，而是因为你足够&quot;够格&quot;。再说，每个团队都有各种level的人，你只需要跟自己比有进步就好。</p><h3 id="拆解-不够格-幻觉" tabindex="-1">拆解&quot;不够格&quot;幻觉 <a class="header-anchor" href="#拆解-不够格-幻觉" aria-label="Permalink to &quot;拆解&quot;不够格&quot;幻觉&quot;">​</a></h3><p>&quot;不够格&quot;是一种典型的认知偏差。让我帮你拆解一下。</p><p><strong>幻觉1：&quot;他们要求很高，我达不到&quot;</strong></p><p>实际情况：招聘写的要求是&quot;理想候选人&quot;的画像，不是实际录用标准。真实世界的招聘是&quot;矬子里拔将军&quot;，有60%匹配度就可以投了。</p><p><strong>幻觉2：&quot;我知识储备不够，还需要继续学习&quot;</strong></p><p>实际情况：你永远不会觉得自己&quot;准备好了&quot;。因为AI领域的知识边界在不断扩展，你永远处于&quot;不够&quot;的状态。与其等一个永远不会来的&quot;准备好&quot;，不如先上车再说。</p><p><strong>幻觉3：&quot;进去之后万一露馅怎么办&quot;</strong></p><p>实际情况：每个新人都会&quot;露馅&quot;——表现出不知道某件事，这是正常的。你要做的是快速学习、尽快补上，而不是假装自己什么都知道。坦诚&quot;这个我不太清楚，但我可以学&quot;，比硬撑强一百倍。</p><p><strong>幻觉4：&quot;跨行过来的肯定不如科班出身的&quot;</strong></p><p>实际情况：这是最大的幻觉。据我的观察，AI应用开发做得好的，反而很多是跨行者。因为他们有&quot;领域知识&quot;（Domain Knowledge），这是纯技术背景的人不具备的。</p><p>一个例子：有个做医疗AI的团队，最厉害的工程师不是计算机背景的，而是一个学生物医学工程的转行者。他懂医疗行业、懂医生的工作流程、知道什么信息对决策有用——这些东西是纯程序员学三年也学不会的。</p><h3 id="跟-不够格-感和平共处" tabindex="-1">跟&quot;不够格&quot;感和平共处 <a class="header-anchor" href="#跟-不够格-感和平共处" aria-label="Permalink to &quot;跟&quot;不够格&quot;感和平共处&quot;">​</a></h3><p>我不打算给你灌&quot;你要自信&quot;&quot;你要相信自己&quot;这种鸡汤。真正的自信不是靠喊口号喊出来的，是靠一次次&quot;做到&quot;积累出来的。</p><p>但我可以给你几个实用的心理策略：</p><p><strong>策略1：把&quot;不够格&quot;当作信号，而不是结论</strong></p><p>当你觉得&quot;我不够格&quot;的时候，把它当成一个信号：这个领域有我不知道的东西，我需要学习。而不是当作一个结论：我永远不够格。</p><p><strong>策略2：量化你的&quot;够格度&quot;</strong></p><p>&quot;不够格&quot;是个模糊的感觉。试着把它量化：我知道什么？我做过什么？对比JD，我满足了哪些？</p><p>大概率你会发现，你比你自己以为的&quot;够格&quot;得多。</p><p><strong>策略3：找一个&quot;成长参照&quot;而不是&quot;完美参照&quot;</strong></p><p>不要跟行业顶尖比。找一个跟你背景相似、比你早入行1-2年的人，看看他当初是什么样的状态。往往你会发现，你现在可能已经超过他当初的水平了。</p><p><strong>策略4：接受&quot;边干边学&quot;是常态</strong></p><p>没有什么&quot;准备好了才能干&quot;的事情。你现在做的工作，就是在学习。工作中的挑战就是你的教科书。每个你解决的问题都是一次进步。</p><p><strong>策略5：给自己写一份&quot;成就清单&quot;</strong></p><p>每周记录你解决的问题、你学到的技能、你交付的成果。月底回顾一下，你会发现其实你进步很快。&quot;不够格&quot;感会让你忘记自己做过的事情，成就清单能帮你客观看到自己的成长。</p><h3 id="从-冒名顶替-到-真名顶替" tabindex="-1">从&quot;冒名顶替&quot;到&quot;真名顶替&quot; <a class="header-anchor" href="#从-冒名顶替-到-真名顶替" aria-label="Permalink to &quot;从&quot;冒名顶替&quot;到&quot;真名顶替&quot;&quot;">​</a></h3><p>其实有个秘密：大部分&quot;感觉自己不够格&quot;的人，最后都发现自己其实挺够格的。</p><p>那些真正不够格的人，反而很少有这种感觉——因为他们不知道自己不知道。</p><p>所以，当你感觉&quot;我是冒名顶替者&quot;的时候，恰恰说明你不是。你在乎、你谨慎、你认真对待这份工作。</p><p>这恰恰是优点，不是缺点。</p><hr><h2 id="本章行动清单" tabindex="-1">本章行动清单 <a class="header-anchor" href="#本章行动清单" aria-label="Permalink to &quot;本章行动清单&quot;">​</a></h2><ol><li><p><strong>重新评估你的&quot;准备时间&quot;</strong></p><p>不要再想&quot;我还需要学多久才能准备充分&quot;。转而问自己：**我现在能不能开始做第一个AI相关的项目？**如果答案是&quot;可以做出一个demo&quot;，那就够了。</p></li><li><p><strong>做一个小到不可能失败的切入行动</strong></p><p>找一个AI相关的开源项目，clone下来，跑通，修改一个bug，提一个PR。这不是为了做出什么成果，是为了建立&quot;我能做这件事&quot;的信心。</p></li><li><p><strong>把简历上的项目经历改成&quot;做过什么&quot;而不是&quot;会什么&quot;</strong></p><p>企业要的是成果，不是技能清单。哪怕是一个很小的demo，也是&quot;项目经验&quot;。</p></li><li><p><strong>开始投简历，不要等准备好</strong></p><p>投简历本身就是学习过程。你会在面试中发现自己的短板，这才是最有效的复习。每一场面试都是一次免费的学习机会。</p></li><li><p><strong>给自己设计一个&quot;即时学习&quot;流程</strong></p><p>不要系统学习，要问题驱动。遇到问题 → 快速了解最小必要知识 → 解决问题 → 总结复盘。这个循环比&quot;先学完再做&quot;效率高3倍。</p></li><li><p><strong>写一份&quot;成就清单&quot;，每周更新</strong></p><p>每解决一个问题、每学会一个技能，都记下来。月底回顾，你会发现自己比想象中进步快很多。</p></li><li><p><strong>遇到&quot;我不够格&quot;的想法时，执行&quot;量化检验&quot;</strong></p><p>把模糊的焦虑转化为具体的问题：这个岗位要求什么？我现在满足几条？我的demo能展示什么？用数据打败幻觉。</p></li></ol><hr><blockquote><p><strong>下章预告</strong>：第三章我会给你画一张完整的入行路线图——不管你是后端转AI、前端转AI、零基础、还是在校学生，都能找到适合自己的那条路。还有具体的8周入行冲刺计划和6个月深耕计划。</p></blockquote>',171)])])}const h=o(n,[["render",q]]);export{d as __pageData,h as default};
